#include<bits/stdc++.h>
using namespace std;
const int f[10]={0,-1,1,7,4,2,6,8,10};
int T,n,d,i;
int main(){
	for(cin>>T;T--;){
		cin>>n;
		if(n<=8)cout<<f[n];
		else{
			d=n%7;
			if(!d)for(i=1;i<=n/7;i++)cout<<8;
			if(d==1){
				cout<<10;
				for(i=1;i<n/7;i++)cout<<8;
			}
			if(d==2){
				cout<<1;
				for(i=1;i<=n/7;i++)cout<<8;
			}
			if(d==3){
				if(n==10)cout<<22;
				else{
					cout<<200;
					for(i=1;i<=n/7-2;i++)cout<<8;
				}
			}
			if(d==4){
				cout<<20;
				for(i=1;i<n/7;i++)cout<<8;
			}
			if(d==5){
				cout<<2;
				for(i=1;i<=n/7;i++)cout<<8;
			}
			if(d==6){
				cout<<6;
				for(i=1;i<=n/7;i++)cout<<8;
			}
		}
		cout<<'\n';
	}
}
